        let dangling_comments = comments_info.dangling(item);

        write!(
            f,
            [clause(
                ClauseHeader::ExceptHandler(item),
                &format_with(|f: &mut PyFormatter| {
                    write!(
                        f,
                        [
                            token("except"),
                            match except_handler_kind {
